                      import sailpoint.object.QueryOptions;
                      import sailpoint.object.Filter;

                      if(null == value || value.isEmpty())
                      {
                      	value = new ArrayList();
                      	value.add("peopleSoftCertificationCreation");
                      	value.add("peopleSoftCertificationEnding");
                      }
                      queryOptions.addFilter(Filter.in("action", value));
                      
                      return queryOptions;

                      import sailpoint.object.QueryOptions;
                      import sailpoint.object.Filter;

                      queryOptions.addFilter(Filter.eq("application", value));
                      return queryOptions;

RenderScript.Source:
                    import org.apache.log4j.Logger;
                    import sailpoint.object.AuditEvent;

                    Logger logger = Logger.getLogger("rule.Ascension.fodLocation.ReportPeopleSoftAttestation");

                    logger.debug("##################### -PeopleoftAttestation starts ##################### ");

                    logger.debug("#####################  renderCache = " +  renderCache);

                    AuditEvent event = context.getObjectById(AuditEvent.class, value);
                    if(null != event)
                    {
                      logger.debug("#####################  event = " +  event.toXml());
                      renderCache.put("actionStatus", event.getAttribute("actionStatus"));
                      renderCache.put("certificationOwner", event.getAttribute("certificationOwner"));
                      renderCache.put("certifierDisplayName", event.getAttribute("certifierDisplayName"));
                      renderCache.put("certifierEmail", event.getAttribute("certifierEmail"));
                      renderCache.put("certifierEmployeeId", event.getAttribute("certifierEmployeeId"));
                      renderCache.put("entitlementValue", event.getAttribute("entitlementValue"));
                      renderCache.put("targetUserDisplayName", event.getAttribute("targetUserDisplayName"));
                      renderCache.put("targetUserId", event.getAttribute("targetUserId"));
                      renderCache.put("targetUserSAMAccName", event.getAttribute("targetUserSAMAccName"));
              				renderCache.put("certifierPhone", event.getAttribute("certifierPhone"));
                    }

                    return renderCache.get("actionStatus");
